import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as n,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Other/auto-tagging.md","filePath":"id-ID/Other/auto-tagging.md","lastUpdated":1781962217000}'),r={name:"id-ID/Other/auto-tagging.md"};function d(g,a,l,p,o,u){return n(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging dikonfigurasi di:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Fitur ini membuat tag gambar secara otomatis. Tag tersebut berguna untuk pencarian, filter random image, filter public gallery, dan kontrol akses berdasarkan rating usia.</p><h2 id="yang-bisa-dilakukan-auto-tagging" tabindex="-1">Yang Bisa Dilakukan Auto Tagging <a class="header-anchor" href="#yang-bisa-dilakukan-auto-tagging" aria-label="Permalink to &quot;Yang Bisa Dilakukan Auto Tagging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fitur</th><th>Keterangan</th></tr></thead><tbody><tr><td>Membuat tag konten</td><td>Menambahkan tag untuk orang, suasana, objek, gaya ilustrasi, dan isi visual sejenis.</td></tr><tr><td>Membuat tag karakter</td><td>Berguna untuk gambar anime dan ilustrasi.</td></tr><tr><td>Menambahkan tag orientasi</td><td>Menambahkan <code>landscape</code>, <code>portrait</code>, atau <code>square</code>.</td></tr><tr><td>Menambahkan rating gambar</td><td>Menyimpan hasil rating <code>G/S/Q/E</code> untuk konten umum, sensitif, meragukan, atau eksplisit.</td></tr><tr><td>Auto-tag saat upload</td><td>Gambar baru otomatis masuk ke proses tagging.</td></tr><tr><td>Batch tagging</td><td>Menambahkan tag ke gambar lama di semua folder atau folder tertentu.</td></tr></tbody></table><h2 id="yang-perlu-disiapkan" tabindex="-1">Yang Perlu Disiapkan <a class="header-anchor" href="#yang-perlu-disiapkan" aria-label="Permalink to &quot;Yang Perlu Disiapkan&quot;">​</a></h2><p>Siapkan minimal satu URL Hugging Face Space yang bisa diakses.</p><p>Cara yang paling disarankan adalah menggandakan Space <code>wd-tagger</code> milik SmilingWolf ke akun Hugging Face Anda sendiri:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Anda bisa memakai Space publik untuk uji coba sementara, tetapi Space publik dipakai banyak orang. Antrean bisa panjang, respons bisa lambat, atau sewaktu-waktu tidak tersedia. Space hasil duplikasi di akun sendiri biasanya lebih stabil untuk pemakaian jangka panjang.</p><h2 id="menggandakan-space-smilingwolf" tabindex="-1">Menggandakan Space SmilingWolf <a class="header-anchor" href="#menggandakan-space-smilingwolf" aria-label="Permalink to &quot;Menggandakan Space SmilingWolf&quot;">​</a></h2><ol><li>Masuk ke Hugging Face.</li><li>Buka <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+e+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Klik menu tiga titik di kanan atas.</li><li>Pilih <code>Duplicate this Space</code>.</li><li>Gunakan nama Space bawaan atau isi nama sendiri, misalnya <code>wd-tagger</code>.</li><li>Atur visibility menjadi <code>Public</code>. Public Space lebih mudah dipanggil oleh ImgBed.</li><li>Untuk awal, biarkan hardware gratis bawaan. Upgrade hanya jika antrean sudah terasa mengganggu.</li><li>Buat Space dan tunggu proses build selesai.</li></ol><p>Setelah build selesai, buka halaman Space Anda. URL biasanya berbentuk seperti ini:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Salin URL dari browser, lalu tempelkan ke <code>Space URLs</code> di ImgBed.</p><h2 id="mengisi-beberapa-space-url" tabindex="-1">Mengisi Beberapa Space URL <a class="header-anchor" href="#mengisi-beberapa-space-url" aria-label="Permalink to &quot;Mengisi Beberapa Space URL&quot;">​</a></h2><p>Masukkan satu Space URL per baris.</p><p>Contoh:</p><table tabindex="0"><thead><tr><th>Nilai</th><th>Keterangan</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Space publik SmilingWolf. Cocok untuk tes sementara.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL halaman Space yang sudah disalin.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Space duplikasi milik Anda sendiri.</td></tr></tbody></table><p>Anda boleh memasukkan beberapa URL. ImgBed akan memakai beberapa Space secara bersamaan, sehingga proses bisa lebih cepat.</p><p>Jika salah satu Space sedang tidak tersedia, Space lain tetap bisa melanjutkan pemrosesan.</p><h2 id="pengaturan" tabindex="-1">Pengaturan <a class="header-anchor" href="#pengaturan" aria-label="Permalink to &quot;Pengaturan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Rekomendasi</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Masukkan Space URL yang sudah disiapkan. Pakai minimal satu.</td></tr><tr><td>Target folder</td><td>Kosongkan untuk semua folder. Pilih folder hanya jika ingin memproses direktori tertentu.</td></tr><tr><td>Recognition model</td><td>Biarkan <code>wd-swinv2-tagger-v3</code> sebagai default.</td></tr><tr><td>General tag threshold</td><td>Nilai default cocok untuk sebagian besar gambar. Nilai lebih rendah menghasilkan lebih banyak tag; nilai lebih tinggi menghasilkan lebih sedikit tag.</td></tr><tr><td>Character tag threshold</td><td>Default cukup konservatif dan membantu mengurangi tag karakter yang keliru.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Matikan dulu. Aktifkan jika ingin model menentukan jumlah tag secara otomatis.</td></tr><tr><td>Auto-tag on upload</td><td>Aktifkan jika gambar baru perlu diberi tag otomatis setelah upload.</td></tr><tr><td>Start tagging</td><td>Menjalankan batch-tagging manual untuk gambar lama.</td></tr></tbody></table><h2 id="nilai-awal-yang-disarankan" tabindex="-1">Nilai Awal yang Disarankan <a class="header-anchor" href="#nilai-awal-yang-disarankan" aria-label="Permalink to &quot;Nilai Awal yang Disarankan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opsi</th><th>Nilai yang Disarankan</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Matikan dulu</td></tr><tr><td>Auto-tag on upload</td><td>Aktifkan bila diperlukan</td></tr></tbody></table><p>Jika tag yang keluar terlalu banyak, naikkan sedikit general threshold.</p><p>Jika tag terlalu sedikit, turunkan sedikit general threshold.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>Isi <code>Space URLs</code>.</li><li>Pilih target folder.</li><li>Klik start tagging.</li><li>Tunggu sampai progress selesai.</li></ol><p>Jika target folder kosong, ImgBed akan memproses semua folder.</p><p>Batch tagging paling cocok untuk gambar lama. Untuk gambar baru, aktifkan auto-tag on upload agar tidak perlu menjalankannya manual setiap kali.</p><h2 id="auto-tag-saat-upload" tabindex="-1">Auto-Tag Saat Upload <a class="header-anchor" href="#auto-tag-saat-upload" aria-label="Permalink to &quot;Auto-Tag Saat Upload&quot;">​</a></h2><p>Setelah auto-tag on upload diaktifkan, gambar yang baru diupload otomatis memanggil <code>Space URLs</code> yang sudah dikonfigurasi.</p><p>Ini cocok untuk pemakaian jangka panjang.</p><p>Jika Space sedang antre, upload tetap bisa selesai lebih dulu, lalu tagging dilanjutkan di belakang.</p><h2 id="gambar-yang-diproses" tabindex="-1">Gambar yang Diproses <a class="header-anchor" href="#gambar-yang-diproses" aria-label="Permalink to &quot;Gambar yang Diproses&quot;">​</a></h2><p>Auto tagging terutama memproses file gambar.</p><p>Gambar yang sudah memiliki tag lengkap, orientasi, rating, lebar, dan tinggi akan dilewati agar tidak memanggil Space tanpa perlu.</p><p>Jika memungkinkan, ImgBed hanya melengkapi informasi yang belum ada. Misalnya jika hanya orientasi yang belum ada, ImgBed akan mencoba menambahkan orientasi tanpa menjalankan seluruh alur content tag.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="kenapa-perlu-menggandakan-space-sendiri" tabindex="-1">Kenapa Perlu Menggandakan Space Sendiri? <a class="header-anchor" href="#kenapa-perlu-menggandakan-space-sendiri" aria-label="Permalink to &quot;Kenapa Perlu Menggandakan Space Sendiri?&quot;">​</a></h3><p>Space publik dipakai banyak orang. Space duplikasi milik Anda biasanya hanya dipakai oleh situs ImgBed Anda, sehingga umumnya lebih cepat dan lebih stabil.</p><h3 id="space-terus-berstatus-starting-up" tabindex="-1">Space Terus Berstatus Starting Up <a class="header-anchor" href="#space-terus-berstatus-starting-up" aria-label="Permalink to &quot;Space Terus Berstatus Starting Up&quot;">​</a></h3><p>Setelah pertama kali dibuat, atau setelah lama tidak dipakai, Space mungkin butuh waktu untuk menyala.</p><p>Buka halaman Space Anda terlebih dahulu. Setelah Space bisa mengenali gambar secara normal, kembali ke ImgBed dan mulai tagging.</p><h3 id="bagaimana-cara-menyalin-space-url" tabindex="-1">Bagaimana Cara Menyalin Space URL? <a class="header-anchor" href="#bagaimana-cara-menyalin-space-url" aria-label="Permalink to &quot;Bagaimana Cara Menyalin Space URL?&quot;">​</a></h3><p>Buka halaman Hugging Face Space Anda dan salin alamat dari browser.</p><p>Contoh:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="bisa-menambahkan-beberapa-space" tabindex="-1">Bisa Menambahkan Beberapa Space? <a class="header-anchor" href="#bisa-menambahkan-beberapa-space" aria-label="Permalink to &quot;Bisa Menambahkan Beberapa Space?&quot;">​</a></h3><p>Bisa. Masukkan satu Space URL per baris.</p><p>Beberapa Space akan memproses gambar bersama-sama dan berguna jika jumlah gambar banyak.</p><h3 id="kenapa-tag-menggunakan-bahasa-inggris" tabindex="-1">Kenapa Tag Menggunakan Bahasa Inggris? <a class="header-anchor" href="#kenapa-tag-menggunakan-bahasa-inggris" aria-label="Permalink to &quot;Kenapa Tag Menggunakan Bahasa Inggris?&quot;">​</a></h3><p>Model SmilingWolf memang menghasilkan tag berbahasa Inggris. Ini normal.</p><p>Tag tersebut terutama dipakai untuk pencarian, filter, Random Image API, dan filter public gallery.</p><h3 id="rating-tag-dipakai-untuk-apa" tabindex="-1">Rating Tag Dipakai Untuk Apa? <a class="header-anchor" href="#rating-tag-dipakai-untuk-apa" aria-label="Permalink to &quot;Rating Tag Dipakai Untuk Apa?&quot;">​</a></h3><p>Hasil rating bekerja bersama access mode di Security Settings.</p><p>Misalnya saat akses pengunjung dibatasi berdasarkan rating usia, fitur public browsing dan random image akan memfilter gambar mengikuti aturan tersebut.</p><h2 id="alur-cepat" tabindex="-1">Alur Cepat <a class="header-anchor" href="#alur-cepat" aria-label="Permalink to &quot;Alur Cepat&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Masuk ke Hugging Face</span></span>
<span class="line"><span>-&gt; Buka SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Tunggu Space selesai build</span></span>
<span class="line"><span>-&gt; Salin Space URL Anda</span></span>
<span class="line"><span>-&gt; Isi Space URLs di ImgBed</span></span>
<span class="line"><span>-&gt; Pilih model dan threshold</span></span>
<span class="line"><span>-&gt; Start tagging atau aktifkan auto-tag on upload</span></span></code></pre></div>`,63)])])}const m=t(r,[["render",d]]);export{k as __pageData,m as default};
